SELECT fixation_id, AVG(pupil_size) as average_pupil_size
FROM fixations
GROUP BY fixation_id;

SELECT AVG(pupil_size) as average_pupil_size
FROM fixations
WHERE duration > 1000;

SELECT experiment_group, COUNT(DISTINCT participant_id) AS NumberOfParticipants
FROM participants
GROUP BY experiment_group;

SELECT trial_id, MAX(duration) AS max_fixation_duration
FROM fixations
GROUP BY trial_id;
